function Navbar({ cart }) {
    return (
      <div style={styles.navbar}>
        <h2>Mini E-commerce</h2>
        <div>🛒 Cart: {cart.length}</div>
      </div>
    );
  }

  const styles = {
    navbar: {
      display: "flex",
      justifyContent: "space-between",
      padding: "15px",
      backgroundColor: "#333",
      color: "white"
    }
  };

  export default Navbar;
